{
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "type": "AdaptiveCard",
  "version": "1.5",
  "body": [
    {
      "type": "TextBlock",
      "text": "🔔 Incident Approval Required",
      "weight": "Bolder",
      "size": "Medium",
      "color": "Attention"
    },
    {
      "type": "TextBlock",
      "text": "An incident has been marked as True Positive and requires your approval to proceed with notifying the primary contacts.",
      "wrap": true
    },
    {
      "type": "FactSet",
      "facts": [
 {
          "title": "Client:",
          "value": "@{parameters('Client Name')}"
        },
        {
          "title": "Incident ID:",
          "value": "@{triggerBody()?['object']?['properties']?['incidentNumber']}"
        },
        {
          "title": "Title:",
          "value": "@{triggerBody()?['object']?['properties']?['title']}"
        },
        {
          "title": "Severity:",
          "value": "@{triggerBody()?['object']?['properties']?['severity']}"
        },
        {
          "title": "Detected Time:",
          "value": "@{formatDateTime(convertTimeZone(triggerBody()?['object']?['properties']?['createdTimeUtc'], 'UTC', 'GMT Standard Time'), 'dd/MM/yyyy hh:mm tt')
}"
        }
      ]
    }
  ],
  "actions": [
    {
      "type": "Action.Submit",
      "title": "Approve",
      "data": {
        "response": "Approve"
      }
    },
    {
      "type": "Action.Submit",
      "title": "Reject",
      "data": {
        "response": "Reject"
      }
    }
  ]
}

{
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "type": "AdaptiveCard",
  "version": "1.4",
  "body": [
    {
      "type": "TextBlock",
      "text": "**Security Incident Notification**",
      "weight": "Bolder",
      "size": "Large",
      "color": "Attention"
    },
{
      "type": "TextBlock",
      "text": "Please note that Conosco SOC has classified the following incident as a True Positive.",
      "wrap": true
    },
    {
      "type": "FactSet",
      "facts": [
 {
          "title": "**Client:**",
          "value": "@{parameters('Client Name')}"
        },
        {
          "title": "**Title:**",
          "value": "@{triggerBody()?['object']?['properties']?['title']}"
        },
        {
          "title": "**Initial Findings:**",
          "value": "@{triggerBody()?['object']?['properties']?['classificationComment']}"
        },
        {
          "title": "**Time Detected:**",
          "value": "@{formatDateTime(convertTimeZone(triggerBody()?['object']?['properties']?['createdTimeUtc'], 'UTC', 'GMT Standard Time'), 'dd/MM/yyyy hh:mm tt')}"
        },
        {
          "title": "**Severity:**",
          "value": "@{triggerBody()?['object']?['properties']?['severity']}"
        }
      ]
    },
    {
      "type": "TextBlock",
      "text": "We are conducting further investigation and will provide updates as soon as possible.",
      "wrap": true
    }
  ]
}
